 1	import React, { FC } from 'react';
 2	
 3	import { NodeNetworkStateModel, NodeNetworkStateModelGroupVersionKind } from '@models';
 4	import {
 5	  ResourceIcon,
 6	  Timestamp,
 7	  useAnnotationsModal,
 8	  useLabelsModal,
 9	} from '@openshift-console/dynamic-plugin-sdk';
10	import {
11	  DescriptionList,
12	  Divider,
13	  PageSection,
14	  PageSectionVariants,
15	  Title,
16	} from '@patternfly/react-core';
17	import { V1beta1NodeNetworkState } from '@types';
18	import DetailItem from '@utils/components/DetailItem/DetailItem';
19	import OwnerDetailsItem from '@utils/components/DetailItem/OwnerDetailItem';
20	import MetadataLabels from '@utils/components/MetadataLabels/MetadataLabels';
21	import { useNMStateTranslation } from '@utils/hooks/useNMStateTranslation';
22	
23	type StateDetailsPageProps = {
24	  nns: V1beta1NodeNetworkState;
25	};
26	
27	const StateDetailsPage: FC<StateDetailsPageProps> = ({ nns }) => {
28	  const { t } = useNMStateTranslation();
29	  const launchLabelsModal = useLabelsModal(nns);
30	  const launchAnnotationsModal = useAnnotationsModal(nns);
31	
32	  if (!nns) return null;
33	
34	  const annotationsCount = Object.keys(nns?.metadata?.annotations || {}).length;
35	  const annotationsText = t('{{annotationsCount}} Annotations', {
36	    annotationsCount,
37	  });
38	
39	  return (
40	    <>
41	      <Title className="co-m-pane__heading" headingLevel="h1">
42	        <span className="co-resource-item__resource-name">
43	          <ResourceIcon groupVersionKind={NodeNetworkStateModelGroupVersionKind} />
44	          <span className="co-resource-item__resource-name">{nns?.metadata?.name} </span>
45	        </span>
46	      </Title>
47	      <Divider />
48	      <PageSection variant={PageSectionVariants.light}>
49	        <DescriptionList className="pf-c-description-list">
50	          <DetailItem header={t('Name')} description={nns?.metadata?.name} />
51	          <DetailItem
52	            description={
53	              <MetadataLabels labels={nns?.metadata?.labels} model={NodeNetworkStateModel} />
54	            }
55	            header={t('Labels')}
56	            isEdit
57	            onEditClick={launchLabelsModal}
58	            showEditOnTitle
59	          />
60	          <DetailItem
61	            description={annotationsText}
62	            header={t('Annotations')}
63	            isEdit
64	            onEditClick={launchAnnotationsModal}
65	          />
66	          <DetailItem
67	            description={<Timestamp timestamp={nns?.metadata?.creationTimestamp} />}
68	            header={t('Created at')}
69	          />
70	          <OwnerDetailsItem obj={nns} />
71	        </DescriptionList>
72	      </PageSection>
73	    </>
74	  );
75	};
76	
77	export default StateDetailsPage;

